var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"어디 보자……. 수신기 감도는 양호하고…….","JPN":"どれどれ……受信機の感度は良好……","ENG":"Lemme see here... Signal seems strong...","TWN":"我看看……接收器靈敏度良好……"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"사장님이 빨리 사람을 보내 주면 좋을 텐데, 일단 좌표도 모르니까…","JPN":"社長が早く人を送ってくれたらいいのに、まだ座標も知らないから……","ENG":"I wish Boss would send reinforcements fast. But since I don't even know the coordinates...","TWN":"老闆快點派人過來就好了，但是因為連座標都不知道……"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"외지인님, 간이 맞는지 확인해 주실래요?","JPN":"よそ者様、味見をお願いしてもいいですか？","ENG":"Ms. Rivet? Can you check if the seasoning's good please?","TWN":"外地人，你能幫忙嘗一下味道嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"그런 의뢰라면야 언제든 환영이지.","JPN":"そういう依頼ならいつでも歓迎だよ。","ENG":"For stuff like that, you can always ask me!","TWN":"這種忙我隨時歡迎。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"으음, 맛있다~ 엄마가 해 주던 그 맛 그대로야~","JPN":"うーん、おいしい～お母さんの味とそっくり～","ENG":"Mm... It's so good! It tastes just like how my mom would make it!","TWN":"呃嗯，真好吃～跟我媽媽做的味道一模一樣～"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"다행이다. 쓸 수 있는 조미료가 별로 없어서 걱정했거든요.","JPN":"よかった。使える調味料があまりなかったので不安だったんです。","ENG":"That's good to hear. I was worried because there weren’t many spices to use around here.","TWN":"太好了，因為能用的調味料不多，我還擔心不好吃呢。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"사장님도 어떠세요? 한 입 드셔 보실래요?","JPN":"社長もどうです？　一口食べてみますか？","ENG":"What about you, Boss? Would you also like a bite?","TWN":"老闆你呢？也要嚐一口嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 고맙지만 사양하지. 갑 버드는 이 윤활유로 충분하다네.","JPN":"はは、ありがたいが遠慮しよう。甲バードはこの潤滑油で十分さ。","ENG":"Haha. Thank you, but I'll decline. Oil is enough for G.A.P. Bird.","TWN":"哈哈，謝謝，不過不用了。機甲·鳥有潤滑油就夠了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……다들 안 쉬고 뭐 하는 거죠?","JPN":"……みなさん、休まずに何をしているのですか？","ENG":"...What are you all doing and not resting?","TWN":"……大家不休息，都忙什麼呢？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"아, 레지나. 잘 잤어?","JPN":"あ、レジーナ。よく眠れた？","ENG":"Oh, hi Regina. Did you sleep well?","TWN":"啊，蕾佳娜，你睡醒了？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"한동안은 이 쇠파이프 써. 지팡이로 괜찮을 것 같더라.","JPN":"しばらくはこの鉄パイプを使いなよ。杖によさそうだから。","ENG":"Here, use this metal pipe. It’ll make a pretty decent walking stick.","TWN":"暫時先用這根鐵管吧。當拐杖好像不錯。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"여기 와서 앉으세요, 부학회장님.","JPN":"こちらの席にどうぞ、副学会長様。","ENG":"Come over here and sit, Ms. Vice President.","TWN":"你來這邊坐，副學會長。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"식사를 차리던 중이었어요. 외지인님이 갖고 계신 식량으로요.","JPN":"食事の準備をしていました。よそ者様が持っていらっしゃった食糧で。","ENG":"I'm just about done making our meal with what Ms. Rivet had with her.","TWN":"我們正在做飯，用外地人帶的糧食。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"정확히는 보존식이야. 원래는 먹고 토하지 않을 정도의 맛이지만.","JPN":"正確には保存食ね。元々は食べてぎり吐かないくらいの味だけど。","ENG":"Technically, it's just preserved food. And they taste just enough for you to not barf it all out.","TWN":"準確地說是冷凍食品。雖然味道只是吃完不會吐的那種。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"자, 아~ 해 보실래요?","JPN":"はい、あ～んしてください。","ENG":"Now then. Say, \\"ah\\".","TWN":"來，啊～嚐一口吧？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"제가 알아서 먹을 테니까 그만둬요, 실키. 다 큰 나이에 부끄럽게.","JPN":"自分で食べますからやめてください、シルキー。恥ずかしいですわ。","ENG":"I am capable of eating on my own, Sylkie. I am not a baby.","TWN":"我會自己吃，不用你餵，思琪。這也太多難為情了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"난 괜찮은데? 이 참에 마저 응석 부려도 돼.","JPN":"アタシは気にしないよ？　この際、甘えちゃいなよ。","ENG":"I wouldn't mind. Why not act like one when you can, Regina?","TWN":"我沒關係啊？你可以趁這個機會繼續撒嬌。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};